window.KJV1769_STRONG_BOOKS["Eph"] = {"osis":"Eph","book":"에베소서","verses":{"1:1":{"text":"Paul, an apostle of Jesus Christ by the will of God, to the saints which are at Ephesus, and to the faithful in Christ Jesus:","words":[["G3972","Paul",0,4],["G0652","an apostle",6,16],["G2424","of Jesus",17,25],["G5547","Christ",26,32],["G1223","by",33,35],["G2307","the will",36,44],["G2316","of God",45,51],["G0040","to the saints",53,66],["G5607","which are",67,76],["G1722","at",77,79],["G2181","Ephesus",80,87],["G2532","and",89,92],["G4103","to the faithful",93,108],["G1722","in",109,111],["G5547","Christ",112,118],["G2424","Jesus",119,124]]},"1:2":{"text":"Grace be to you, and peace, from God our Father, and from the Lord Jesus Christ.","words":[["G5485","Grace",0,5],["G5213","be to you",6,15],["G2532","and",17,20],["G1515","peace",21,26],["G0575","from",28,32],["G2316","God",33,36],["G2257","our",37,40],["G3962","Father",41,47],["G2532","and",49,52],["G2962","from the Lord",53,66],["G2424","Jesus",67,72],["G5547","Christ",73,79]]},"1:3":{"text":"Blessed be the God and Father of our Lord Jesus Christ, who hath blessed us with all spiritual blessings in heavenly places in Christ:","words":[["G2128","Blessed",0,7],["G2316","be the God",8,18],["G2532","and",19,22],["G3962","Father",23,29],["G2257","of our",30,36],["G2962","Lord",37,41],["G2424","Jesus",42,47],["G5547","Christ",48,54],["G3588","who",56,59],["G2127","hath blessed",60,72],["G2248","us",73,75],["G1722","with",76,80],["G3956","all",81,84],["G4152","spiritual",85,94],["G2129","blessings",95,104],["G1722","in",105,107],["G2032","heavenly",108,116],["G1722","places in",117,126],["G5547","Christ",127,133]]},"1:4":{"text":"According as he hath chosen us in him before the foundation of the world, that we should be holy and without blame before him in love:","words":[["G2531","According as",0,12],["G1586","he hath chosen",13,27],["G2248","us",28,30],["G1722","in",31,33],["G0846","him",34,37],["G4253","before",38,44],["G2602","the foundation",45,59],["G2889","of the world",60,72],["G2248","that we",74,81],["G1511","should be",82,91],["G0040","holy",92,96],["G2532","and",97,100],["G0299","without blame",101,114],["G2714","before",115,121],["G0846","him",122,125],["G1722","in",126,128],["G0026","love",129,133]]},"1:5":{"text":"Having predestinated us unto the adoption of children by Jesus Christ to himself, according to the good pleasure of his will,","words":[["G4309","Having predestinated",0,20],["G2248","us",21,23],["G1519","unto",24,28],["G5206","the adoption of children",29,53],["G1223","by",54,56],["G2424","Jesus",57,62],["G5547","Christ",63,69],["G1519","to",70,72],["G0846","himself",73,80],["G2596","according",82,91],["G2107","to the good pleasure",92,112],["G0846","of his",113,119],["G2307","will",120,124]]},"1:6":{"text":"To the praise of the glory of his grace, wherein he hath made us accepted in the beloved.","words":[["G1519","To",0,2],["G1868","the praise",3,13],["G1391","of the glory",14,26],["G0846","of his",27,33],["G5485","grace",34,39],["G1722","wherein",41,48],["G3739","wherein",41,48],["G5487","he hath made",49,61],["G2248","us",62,64],["G5487","accepted",65,73],["G1722","in",74,76],["G0025","the beloved",77,88]]},"1:7":{"text":"In whom we have redemption through his blood, the forgiveness of sins, according to the riches of his grace;","words":[["G1722","In",0,2],["G3739","whom",3,7],["G2192","we have",8,15],["G0629","redemption",16,26],["G1223","through",27,34],["G0846","his",35,38],["G0129","blood",39,44],["G0859","the forgiveness",46,61],["G3900","of sins",62,69],["G2596","according",71,80],["G4149","to the riches",81,94],["G0846","of his",95,101],["G5485","grace",102,107]]},"1:8":{"text":"Wherein he hath abounded toward us in all wisdom and prudence;","words":[["G3739","Wherein",0,7],["G4052","he hath abounded",8,24],["G1519","toward",25,31],["G2248","us",32,34],["G1722","in",35,37],["G3956","all",38,41],["G4678","wisdom",42,48],["G2532","and",49,52],["G5428","prudence",53,61]]},"1:9":{"text":"Having made known unto us the mystery of his will, according to his good pleasure which he hath purposed in himself:","words":[["G1107","Having made known",0,17],["G2254","unto us",18,25],["G3466","the mystery",26,37],["G0846","of his",38,44],["G2307","will",45,49],["G2596","according to",51,63],["G0846","his",64,67],["G2107","good pleasure",68,81],["G3739","which",82,87],["G4388","he hath purposed",88,104],["G1722","in",105,107],["G0846","himself",108,115]]},"1:10":{"text":"That in the dispensation of the fulness of times he might gather together in one all things in Christ, both which are in heaven, and which are on earth; even in him:","words":[["G1519","That in",0,7],["G3622","the dispensation",8,24],["G4138","of the fulness",25,39],["G2540","of times",40,48],["G0346","he might gather together in one",49,80],["G3956","all things",81,91],["G1722","in",92,94],["G5547","Christ",95,101],["G5037","both",103,107],["G3588","which",108,113],["G1722","are in",114,120],["G3772","heaven",121,127],["G2532","and",129,132],["G3588","which",133,138],["G1909","are on",139,145],["G1093","earth",146,151],["G1722","even in",153,160],["G0846","him",161,164]]},"1:11":{"text":"In whom also we have obtained an inheritance, being predestinated according to the purpose of him who worketh all things after the counsel of his own will:","words":[["G1722","In",0,2],["G3739","whom",3,7],["G2532","also",8,12],["G2820","we have obtained an inheritance",13,44],["G4309","being predestinated",46,65],["G2596","according to",66,78],["G4286","the purpose",79,90],["G1754","of him who worketh",91,109],["G3956","all things",110,120],["G2596","after",121,126],["G1012","the counsel",127,138],["G0846","of his own",139,149],["G2307","will",150,154]]},"1:12":{"text":"That we should be to the praise of his glory, who first trusted in Christ.","words":[["G1519","That",0,4],["G2248","we",5,7],["G1511","should be",8,17],["G1519","to",18,20],["G1868","the praise",21,31],["G0846","of his",32,38],["G1391","glory",39,44],["G3588","who",46,49],["G4276","first trusted",50,63],["G1722","in",64,66],["G5547","Christ",67,73]]},"1:13":{"text":"In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,","words":[["G1722","In",0,2],["G3739","whom",3,7],["G5210","ye",8,10],["G2532","also",11,15],["G0191","trusted, after that ye heard",16,44],["G3056","the word",45,53],["G0225","of truth",54,62],["G2098","the gospel",64,74],["G5216","of your",75,82],["G4991","salvation",83,92],["G1722","in",94,96],["G3739","whom",97,101],["G2532","also",102,106],["G4100","after that ye believed",107,129],["G4972","ye were sealed with",131,150],["G0040","that holy",151,160],["G4151","Spirit",161,167],["G1860","of promise",168,178]]},"1:14":{"text":"Which is the earnest of our inheritance until the redemption of the purchased possession, unto the praise of his glory.","words":[["G3739","Which",0,5],["G2076","is",6,8],["G0728","the earnest",9,20],["G2257","of our",21,27],["G2817","inheritance",28,39],["G1519","until",40,45],["G0629","the redemption",46,60],["G4047","of the purchased possession",61,88],["G1519","unto",90,94],["G1868","the praise",95,105],["G0846","of his",106,112],["G1391","glory",113,118]]},"1:15":{"text":"Wherefore I also, after I heard of your faith in the Lord Jesus, and love unto all the saints,","words":[["G1223","Wherefore",0,9],["G5124","Wherefore",0,9],["G2504","I also",10,16],["G0191","after I heard",18,31],["G2596","of",32,34],["G5209","your",35,39],["G4102","faith",40,45],["G1722","in",46,48],["G2962","the Lord",49,57],["G2424","Jesus",58,63],["G2532","and",65,68],["G0026","love",69,73],["G1519","unto",74,78],["G3956","all",79,82],["G0040","the saints",83,93]]},"1:16":{"text":"Cease not to give thanks for you, making mention of you in my prayers;","words":[["G3973","Cease",0,5],["G3756","not",6,9],["G2168","to give thanks",10,24],["G5228","for",25,28],["G5216","you",29,32],["G4160","making",34,40],["G3417","mention",41,48],["G5216","of you",49,55],["G1909","in",56,58],["G3450","my",59,61],["G4335","prayers",62,69]]},"1:17":{"text":"That the God of our Lord Jesus Christ, the Father of glory, may give unto you the spirit of wisdom and revelation in the knowledge of him:","words":[["G2443","That",0,4],["G2316","the God",5,12],["G2257","of our",13,19],["G2962","Lord",20,24],["G2424","Jesus",25,30],["G5547","Christ",31,37],["G3962","the Father",39,49],["G1391","of glory",50,58],["G1325","may give",60,68],["G5213","unto you",69,77],["G4151","the spirit",78,88],["G4678","of wisdom",89,98],["G2532","and",99,102],["G0602","revelation",103,113],["G1722","in",114,116],["G1922","the knowledge",117,130],["G0846","of him",131,137]]},"1:18":{"text":"The eyes of your understanding being enlightened; that ye may know what is the hope of his calling, and what the riches of the glory of his inheritance in the saints,","words":[["G3788","The eyes",0,8],["G5216","of your",9,16],["G1271","understanding",17,30],["G5461","being enlightened",31,48],["G1519","that",50,54],["G5209","ye",55,57],["G1492","may know",58,66],["G5101","what",67,71],["G2076","is",72,74],["G1680","the hope",75,83],["G0846","of his",84,90],["G2821","calling",91,98],["G2532","and",100,103],["G5101","what",104,108],["G4149","the riches",109,119],["G1391","of the glory",120,132],["G0846","of his",133,139],["G2817","inheritance",140,151],["G1722","in",152,154],["G0040","the saints",155,165]]},"1:19":{"text":"And what is the exceeding greatness of his power to us-ward who believe, according to the working of his mighty power,","words":[["G2532","And",0,3],["G5101","what",4,8],["G5235","is the exceeding",9,25],["G3174","greatness",26,35],["G0846","of his",36,42],["G1411","power",43,48],["G1519","to",49,51],["G2248","us-ward",52,59],["G3588","who",60,63],["G4100","believe",64,71],["G2596","according to",73,85],["G1753","the working",86,97],["G0846","of his",98,104],["G2479","mighty",105,111],["G2904","power",112,117]]},"1:20":{"text":"Which he wrought in Christ, when he raised him from the dead, and set him at his own right hand in the heavenly places,","words":[["G3739","Which",0,5],["G1754","he wrought",6,16],["G1722","in",17,19],["G5547","Christ",20,26],["G1453","when he raised",28,42],["G0846","him",43,46],["G1537","from",47,51],["G3498","the dead",52,60],["G2532","and",62,65],["G2523","set",66,69],["G1722","him at",70,76],["G0846","his own",77,84],["G1188","right hand",85,95],["G1722","in",96,98],["G2032","the heavenly",99,111]]},"1:21":{"text":"Far above all principality, and power, and might, and dominion, and every name that is named, not only in this world, but also in that which is to come:","words":[["G5231","Far above",0,9],["G3956","all",10,13],["G0746","principality",14,26],["G2532","and",28,31],["G1849","power",32,37],["G2532","and",39,42],["G1411","might",43,48],["G2532","and",50,53],["G2963","dominion",54,62],["G2532","and",64,67],["G3956","every",68,73],["G3686","name",74,78],["G3687","that is named",79,92],["G3756","not",94,97],["G3440","only",98,102],["G1722","in",103,105],["G5129","this",106,110],["G0165","world",111,116],["G0235","but",118,121],["G2532","also",122,126],["G1722","in",127,129],["G3195","that which is to come",130,151]]},"1:22":{"text":"And hath put all things under his feet, and gave him to be the head over all things to the church,","words":[["G2532","And",0,3],["G5293","hath put",4,12],["G3956","all",13,16],["G5259","things under",17,29],["G0846","his",30,33],["G4228","feet",34,38],["G2532","and",40,43],["G1325","gave",44,48],["G0846","him",49,52],["G2776","to be the head",53,67],["G5228","over",68,72],["G3956","all",73,76],["G1577","things to the church",77,97]]},"1:23":{"text":"Which is his body, the fulness of him that filleth all in all.","words":[["G3748","Which",0,5],["G2076","is",6,8],["G0846","his",9,12],["G4983","body",13,17],["G4138","the fulness",19,30],["G4137","of him that filleth",31,50],["G3956","all",51,54],["G1722","in",55,57],["G3956","all",58,61]]},"2:1":{"text":"And you hath he quickened, who were dead in trespasses and sins;","words":[["G2532","And",0,3],["G5209","you",4,7],["G5607","hath he quickened, who were",8,35],["G3498","dead",36,40],["G3900","in trespasses",41,54],["G2532","and",55,58],["G0266","sins",59,63]]},"2:2":{"text":"Wherein in time past ye walked according to the course of this world, according to the prince of the power of the air, the spirit that now worketh in the children of disobedience:","words":[["G1722","Wherein",0,7],["G3739","Wherein",0,7],["G4218","in time past",8,20],["G4043","ye walked",21,30],["G2596","according to",31,43],["G0165","the course",44,54],["G5127","of this",55,62],["G2889","world",63,68],["G2596","according to",70,82],["G0758","the prince",83,93],["G1849","of the power",94,106],["G0109","of the air",107,117],["G4151","the spirit",119,129],["G3568","that now",130,138],["G1754","worketh",139,146],["G1722","in",147,149],["G5207","the children",150,162],["G0543","of disobedience",163,178]]},"2:3":{"text":"Among whom also we all had our conversation in times past in the lusts of our flesh, fulfilling the desires of the flesh and of the mind; and were by nature the children of wrath, even as others.","words":[["G1722","Among",0,5],["G3739","whom",6,10],["G2532","also",11,15],["G2249","we",16,18],["G3956","all",19,22],["G0390","had our conversation",23,43],["G4218","in times past",44,57],["G1722","in",58,60],["G1939","the lusts",61,70],["G2257","of our",71,77],["G4561","flesh",78,83],["G4160","fulfilling",85,95],["G2307","the desires",96,107],["G4561","of the flesh",108,120],["G2532","and",121,124],["G1271","of the mind",125,136],["G2532","and",138,141],["G2258","were",142,146],["G5449","by nature",147,156],["G5043","the children",157,169],["G3709","of wrath",170,178],["G2532","even",180,184],["G5613","as",185,187],["G3062","others",188,194]]},"2:4":{"text":"But God, who is rich in mercy, for his great love wherewith he loved us,","words":[["G1161","But",0,3],["G2316","God",4,7],["G5607","who is",9,15],["G4145","rich",16,20],["G1722","in",21,23],["G1656","mercy",24,29],["G1223","for",31,34],["G0846","his",35,38],["G4183","great",39,44],["G0026","love",45,49],["G3739","wherewith",50,59],["G0025","he loved",60,68],["G2248","us",69,71]]},"2:5":{"text":"Even when we were dead in sins, hath quickened us together with Christ, (by grace ye are saved;)","words":[["G2532","Even",0,4],["G2248","when we",5,12],["G5607","were",13,17],["G3498","dead",18,22],["G3900","in sins",23,30],["G4806","hath quickened us together with",32,63],["G5547","Christ",64,70],["G5485","(by grace",72,81],["G2075","ye are",82,88],["G4982","saved",89,94]]},"2:6":{"text":"And hath raised us up together, and made us sit together in heavenly places in Christ Jesus:","words":[["G2532","And",0,3],["G4891","hath raised us up together",4,30],["G2532","and",32,35],["G4776","made us sit together",36,56],["G1722","in",57,59],["G2032","heavenly",60,68],["G1722","places in",69,78],["G5547","Christ",79,85],["G2424","Jesus",86,91]]},"2:7":{"text":"That in the ages to come he might shew the exceeding riches of his grace in his kindness toward us through Christ Jesus.","words":[["G2443","That",0,4],["G1722","in",5,7],["G0165","the ages",8,16],["G1904","to come",17,24],["G1731","he might shew",25,38],["G5235","the exceeding",39,52],["G4149","riches",53,59],["G0846","of his",60,66],["G5485","grace",67,72],["G1722","in",73,75],["G5544","his kindness",76,88],["G1909","toward",89,95],["G2248","us",96,98],["G1722","through",99,106],["G5547","Christ",107,113],["G2424","Jesus",114,119]]},"2:8":{"text":"For by grace are ye saved through faith; and that not of yourselves: it is the gift of God:","words":[["G1063","For",0,3],["G5485","by grace",4,12],["G2075","are ye",13,19],["G4982","saved",20,25],["G1223","through",26,33],["G4102","faith",34,39],["G2532","and",41,44],["G5124","that",45,49],["G3756","not",50,53],["G1537","of",54,56],["G5216","yourselves",57,67],["G1435","it is the gift",69,83],["G2316","of God",84,90]]},"2:9":{"text":"Not of works, lest any man should boast.","words":[["G3756","Not",0,3],["G1537","of",4,6],["G2041","works",7,12],["G3363","lest",14,18],["G5100","any man",19,26],["G2744","should boast",27,39]]},"2:10":{"text":"For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them.","words":[["G1063","For",0,3],["G2070","we are",4,10],["G0846","his",11,14],["G4161","workmanship",15,26],["G2936","created",28,35],["G1722","in",36,38],["G5547","Christ",39,45],["G2424","Jesus",46,51],["G1909","unto",52,56],["G0018","good",57,61],["G2041","works",62,67],["G3739","which",69,74],["G2316","God",75,78],["G4282","hath before ordained",79,99],["G2443","that",100,104],["G4043","we should walk",105,119],["G1722","in",120,122],["G0846","them",123,127]]},"2:11":{"text":"Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which is called the Circumcision in the flesh made by hands;","words":[["G1352","Wherefore",0,9],["G3421","remember",10,18],["G3754","that",20,24],["G5210","ye",25,27],["G4218","being in time past",28,46],["G1484","Gentiles",47,55],["G1722","in",56,58],["G4561","the flesh",59,68],["G3588","who",70,73],["G3004","are called",74,84],["G0203","Uncircumcision",85,99],["G5259","by",100,102],["G3588","that which",103,113],["G3004","is called",114,123],["G4061","the Circumcision",124,140],["G1722","in",141,143],["G4561","the flesh",144,153],["G5499","made by hands",154,167]]},"2:12":{"text":"That at that time ye were without Christ, being aliens from the commonwealth of Israel, and strangers from the covenants of promise, having no hope, and without God in the world:","words":[["G3754","That",0,4],["G1722","at",5,7],["G1565","that",8,12],["G2540","time",13,17],["G2258","ye were",18,25],["G5565","without",26,33],["G5547","Christ",34,40],["G0526","being aliens",42,54],["G4174","from the commonwealth",55,76],["G2474","of Israel",77,86],["G2532","and",88,91],["G3581","strangers",92,101],["G1242","from the covenants",102,120],["G1860","of promise",121,131],["G2192","having",133,139],["G3361","no",140,142],["G1680","hope",143,147],["G2532","and",149,152],["G0112","without God",153,164],["G1722","in",165,167],["G2889","the world",168,177]]},"2:13":{"text":"But now in Christ Jesus ye who sometimes were far off are made nigh by the blood of Christ.","words":[["G1161","But",0,3],["G3570","now",4,7],["G1722","in",8,10],["G5547","Christ",11,17],["G2424","Jesus",18,23],["G5210","ye",24,26],["G3588","who",27,30],["G4218","sometimes",31,40],["G5607","were",41,45],["G3112","far off",46,53],["G1096","are made",54,62],["G1451","nigh",63,67],["G1722","by",68,70],["G0129","the blood",71,80],["G5547","of Christ",81,90]]},"2:14":{"text":"For he is our peace, who hath made both one, and hath broken down the middle wall of partition between us;","words":[["G1063","For",0,3],["G0846","he",4,6],["G2076","is",7,9],["G2257","our",10,13],["G1515","peace",14,19],["G3588","who",21,24],["G4160","hath made",25,34],["G0297","both",35,39],["G1520","one",40,43],["G2532","and",45,48],["G3089","hath broken down",49,65],["G3320","the middle wall",66,81],["G5418","of partition",82,94]]},"2:15":{"text":"Having abolished in his flesh the enmity, even the law of commandments contained in ordinances; for to make in himself of twain one new man, so making peace;","words":[["G2673","Having abolished",0,16],["G1722","in",17,19],["G0846","his",20,23],["G4561","flesh",24,29],["G2189","the enmity",30,40],["G3551","even the law",42,54],["G1785","of commandments",55,70],["G1722","contained in",71,83],["G1378","ordinances",84,94],["G2443","for to",96,102],["G2936","make",103,107],["G1722","in",108,110],["G1438","himself",111,118],["G1417","of twain",119,127],["G1519","one",128,131],["G1520","one",128,131],["G2537","new",132,135],["G0444","man",136,139],["G4160","so making",141,150],["G1515","peace",151,156]]},"2:16":{"text":"And that he might reconcile both unto God in one body by the cross, having slain the enmity thereby:","words":[["G2532","And",0,3],["G0604","that he might reconcile",4,27],["G0297","both",28,32],["G2316","unto God",33,41],["G1722","in",42,44],["G1520","one",45,48],["G4983","body",49,53],["G1223","by",54,56],["G4716","the cross",57,66],["G0615","having slain",68,80],["G2189","the enmity",81,91],["G1722","thereby",92,99],["G0846","thereby",92,99]]},"2:17":{"text":"And came and preached peace to you which were afar off, and to them that were nigh.","words":[["G2532","And",0,3],["G2064","came",4,8],["G2097","and preached",9,21],["G1515","peace",22,27],["G5213","to you",28,34],["G3588","which",35,40],["G3112","were afar off",41,54],["G2532","and",56,59],["G1451","to them that were nigh",60,82]]},"2:18":{"text":"For through him we both have access by one Spirit unto the Father.","words":[["G3754","For",0,3],["G1223","through",4,11],["G0846","him",12,15],["G2192","we",16,18],["G0297","both",19,23],["G2192","have",24,28],["G4318","access",29,35],["G1722","by",36,38],["G1520","one",39,42],["G4151","Spirit",43,49],["G4314","unto",50,54],["G3962","the Father",55,65]]},"2:19":{"text":"Now therefore ye are no more strangers and foreigners, but fellowcitizens with the saints, and of the household of God;","words":[["G3767","Now",0,3],["G0686","therefore",4,13],["G2075","ye are",14,20],["G3765","no more",21,28],["G3581","strangers",29,38],["G2532","and",39,42],["G3941","foreigners",43,53],["G0235","but",55,58],["G4847","fellowcitizens",59,73],["G0040","with the saints",74,89],["G2532","and",91,94],["G3609","of the household",95,111],["G2316","of God",112,118]]},"2:20":{"text":"And are built upon the foundation of the apostles and prophets, Jesus Christ himself being the chief corner stone;","words":[["G2026","And are built",0,13],["G1909","upon",14,18],["G2310","the foundation",19,33],["G0652","of the apostles",34,49],["G2532","and",50,53],["G4396","prophets",54,62],["G2424","Jesus",64,69],["G5547","Christ",70,76],["G0846","himself",77,84],["G5607","being",85,90],["G0204","the chief corner",91,107]]},"2:21":{"text":"In whom all the building fitly framed together groweth unto an holy temple in the Lord:","words":[["G1722","In",0,2],["G3739","whom",3,7],["G3956","all",8,11],["G3619","the building",12,24],["G4883","fitly framed together",25,46],["G0837","groweth",47,54],["G1519","unto",55,59],["G0040","an holy",60,67],["G3485","temple",68,74],["G1722","in",75,77],["G2962","the Lord",78,86]]},"2:22":{"text":"In whom ye also are builded together for an habitation of God through the Spirit.","words":[["G1722","In",0,2],["G3739","whom",3,7],["G5210","ye",8,10],["G2532","also",11,15],["G4925","are builded together",16,36],["G1519","for",37,40],["G2732","an habitation",41,54],["G2316","of God",55,61],["G1722","through",62,69],["G4151","the Spirit",70,80]]},"3:1":{"text":"For this cause I Paul, the prisoner of Jesus Christ for you Gentiles,","words":[["G5127","For this",0,8],["G5484","cause",9,14],["G1473","I",15,16],["G3972","Paul",17,21],["G1198","the prisoner",23,35],["G2424","of Jesus",36,44],["G5547","Christ",45,51],["G5228","for",52,55],["G5216","you",56,59],["G1484","Gentiles",60,68]]},"3:2":{"text":"If ye have heard of the dispensation of the grace of God which is given me to you-ward:","words":[["G1489","If",0,2],["G0191","ye have heard",3,16],["G3622","of the dispensation",17,36],["G5485","of the grace",37,49],["G2316","of God",50,56],["G3588","which",57,62],["G1325","is given",63,71],["G3427","me",72,74],["G1519","to",75,77],["G5209","you-ward",78,86]]},"3:3":{"text":"How that by revelation he made known unto me the mystery; (as I wrote afore in few words,","words":[["G3754","How that",0,8],["G2596","by",9,11],["G0602","revelation",12,22],["G1107","he made known",23,36],["G3427","unto me",37,44],["G3466","the mystery",45,56],["G2531","(as",58,61],["G4270","I wrote afore",62,75],["G1722","in",76,78],["G3641","few words",79,88]]},"3:4":{"text":"Whereby, when ye read, ye may understand my knowledge in the mystery of Christ)","words":[["G4314","Whereby",0,7],["G3739","Whereby",0,7],["G0314","when ye read",9,21],["G1410","ye may",23,29],["G3539","understand",30,40],["G3450","my",41,43],["G4907","knowledge",44,53],["G1722","in",54,56],["G3466","the mystery",57,68],["G5547","of Christ",69,78]]},"3:5":{"text":"Which in other ages was not made known unto the sons of men, as it is now revealed unto his holy apostles and prophets by the Spirit;","words":[["G3739","Which",0,5],["G1722","in",6,8],["G2087","other",9,14],["G1074","ages",15,19],["G1107","was",20,23],["G3756","not",24,27],["G1107","made known",28,38],["G5207","unto the sons",39,52],["G0444","of men",53,59],["G5613","as",61,63],["G0601","it is",64,69],["G3568","now",70,73],["G0601","revealed",74,82],["G0846","unto his",83,91],["G0040","holy",92,96],["G0652","apostles",97,105],["G2532","and",106,109],["G4396","prophets",110,118],["G1722","by",119,121],["G4151","the Spirit",122,132]]},"3:6":{"text":"That the Gentiles should be fellowheirs, and of the same body, and partakers of his promise in Christ by the gospel:","words":[["G1484","That the Gentiles",0,17],["G1511","should be",18,27],["G4789","fellowheirs",28,39],["G2532","and",41,44],["G4954","of the same body",45,61],["G2532","and",63,66],["G4830","partakers",67,76],["G0846","of his",77,83],["G1860","promise",84,91],["G1722","in",92,94],["G5547","Christ",95,101],["G1223","by",102,104],["G2098","the gospel",105,115]]},"3:7":{"text":"Whereof I was made a minister, according to the gift of the grace of God given unto me by the effectual working of his power.","words":[["G3739","Whereof",0,7],["G1096","I was made",8,18],["G1249","a minister",19,29],["G2596","according",31,40],["G1431","to the gift",41,52],["G5485","of the grace",53,65],["G2316","of God",66,72],["G1325","given",73,78],["G3427","unto me",79,86],["G2596","by",87,89],["G1753","the effectual working",90,111],["G0846","of his",112,118],["G1411","power",119,124]]},"3:8":{"text":"Unto me, who am less than the least of all saints, is this grace given, that I should preach among the Gentiles the unsearchable riches of Christ;","words":[["G1698","Unto me",0,7],["G1647","who am less than the least",9,35],["G3956","of all",36,42],["G0040","saints",43,49],["G1325","is",51,53],["G3778","this",54,58],["G5485","grace",59,64],["G1325","given",65,70],["G2097","that I should preach",72,92],["G1722","among",93,98],["G1484","the Gentiles",99,111],["G0421","the unsearchable",112,128],["G4149","riches",129,135],["G5547","of Christ",136,145]]},"3:9":{"text":"And to make all men see what is the fellowship of the mystery, which from the beginning of the world hath been hid in God, who created all things by Jesus Christ:","words":[["G2532","And",0,3],["G5461","to make",4,11],["G3956","all",12,15],["G5461","men see",16,23],["G5101","what",24,28],["G2842","is the fellowship",29,46],["G3466","of the mystery",47,61],["G3588","which",63,68],["G0575","from",69,73],["G0165","the beginning of the world",74,100],["G0613","hath been hid",101,114],["G1722","in",115,117],["G2316","God",118,121],["G3588","who",123,126],["G2936","created",127,134],["G3956","all things",135,145],["G1223","by",146,148],["G2424","Jesus",149,154],["G5547","Christ",155,161]]},"3:10":{"text":"To the intent that now unto the principalities and powers in heavenly places might be known by the church the manifold wisdom of God,","words":[["G2443","To the intent that",0,18],["G3568","now",19,22],["G0746","unto the principalities",23,46],["G2532","and",47,50],["G1849","powers",51,57],["G1722","in",58,60],["G2032","heavenly",61,69],["G1107","places might be known",70,91],["G1223","by",92,94],["G1577","the church",95,105],["G4182","the manifold",106,118],["G4678","wisdom",119,125],["G2316","of God",126,132]]},"3:11":{"text":"According to the eternal purpose which he purposed in Christ Jesus our Lord:","words":[["G2596","According to",0,12],["G0165","the eternal",13,24],["G4286","purpose",25,32],["G3739","which",33,38],["G4160","he purposed",39,50],["G1722","in",51,53],["G5547","Christ",54,60],["G2424","Jesus",61,66],["G2257","our",67,70],["G2962","Lord",71,75]]},"3:12":{"text":"In whom we have boldness and access with confidence by the faith of him.","words":[["G1722","In",0,2],["G3739","whom",3,7],["G2192","we have",8,15],["G3954","boldness",16,24],["G2532","and",25,28],["G4318","access",29,35],["G1722","with",36,40],["G4006","confidence",41,51],["G1223","by",52,54],["G4102","the faith",55,64],["G0846","of him",65,71]]},"3:13":{"text":"Wherefore I desire that ye faint not at my tribulations for you, which is your glory.","words":[["G1352","Wherefore",0,9],["G0154","I desire",10,18],["G1573","that ye faint",19,32],["G3361","not",33,36],["G1722","at",37,39],["G3450","my",40,42],["G2347","tribulations",43,55],["G5228","for",56,59],["G5216","you",60,63],["G3748","which",65,70],["G2076","is",71,73],["G5216","your",74,78],["G1391","glory",79,84]]},"3:14":{"text":"For this cause I bow my knees unto the Father of our Lord Jesus Christ,","words":[["G5127","For this",0,8],["G5484","cause",9,14],["G2578","I bow",15,20],["G3450","my",21,23],["G1119","knees",24,29],["G4314","unto",30,34],["G3962","the Father",35,45],["G2257","of our",46,52],["G2962","Lord",53,57],["G2424","Jesus",58,63],["G5547","Christ",64,70]]},"3:15":{"text":"Of whom the whole family in heaven and earth is named,","words":[["G1537","Of",0,2],["G3739","whom",3,7],["G3956","the whole",8,17],["G3965","family",18,24],["G1722","in",25,27],["G3772","heaven",28,34],["G2532","and",35,38],["G1909","earth",39,44],["G1093","earth",39,44],["G3687","is named",45,53]]},"3:16":{"text":"That he would grant you, according to the riches of his glory, to be strengthened with might by his Spirit in the inner man;","words":[["G2443","That",0,4],["G1325","he would grant",5,19],["G5213","you",20,23],["G2596","according to",25,37],["G4149","the riches",38,48],["G0846","of his",49,55],["G1391","glory",56,61],["G2901","to be strengthened",63,81],["G1411","with might",82,92],["G1223","by",93,95],["G0846","his",96,99],["G4151","Spirit",100,106],["G1519","in",107,109],["G2080","the inner",110,119],["G0444","man",120,123]]},"3:17":{"text":"That Christ may dwell in your hearts by faith; that ye, being rooted and grounded in love,","words":[["G5547","That Christ",0,11],["G2730","may dwell",12,21],["G1722","in",22,24],["G5216","your",25,29],["G2588","hearts",30,36],["G1223","by",37,39],["G4102","faith",40,45],["G2443","that",47,51],["G4492","ye, being rooted",52,68],["G2532","and",69,72],["G2311","grounded",73,81],["G1722","in",82,84],["G0026","love",85,89]]},"3:18":{"text":"May be able to comprehend with all saints what is the breadth, and length, and depth, and height;","words":[["G1840","May be able",0,11],["G2638","to comprehend",12,25],["G4862","with",26,30],["G3956","all",31,34],["G0040","saints",35,41],["G5101","what",42,46],["G4114","is the breadth",47,61],["G2532","and",63,66],["G3372","length",67,73],["G2532","and",75,78],["G0899","depth",79,84],["G2532","and",86,89],["G5311","height",90,96]]},"3:19":{"text":"And to know the love of Christ, which passeth knowledge, that ye might be filled with all the fulness of God.","words":[["G5037","And",0,3],["G1097","to know",4,11],["G0026","the love",12,20],["G5547","of Christ",21,30],["G5235","which passeth",32,45],["G1108","knowledge",46,55],["G2443","that",57,61],["G4137","ye might be filled",62,80],["G1519","with",81,85],["G3956","all",86,89],["G4138","the fulness",90,101],["G2316","of God",102,108]]},"3:20":{"text":"Now unto him that is able to do exceeding abundantly above all that we ask or think, according to the power that worketh in us,","words":[["G1161","Now",0,3],["G1410","unto him that is able",4,25],["G4160","to do",26,31],["G5228","exceeding",32,41],["G1537","abundantly",42,52],["G4053","abundantly",42,52],["G5228","above",53,58],["G3956","all",59,62],["G3739","that",63,67],["G0154","we ask",68,74],["G2228","or",75,77],["G3539","think",78,83],["G2596","according to",85,97],["G1411","the power",98,107],["G1754","that worketh",108,120],["G1722","in",121,123],["G2254","us",124,126]]},"3:21":{"text":"Unto him be glory in the church by Christ Jesus throughout all ages, world without end. Amen.","words":[["G0846","Unto him",0,8],["G1391","be glory",9,17],["G1722","in",18,20],["G1577","the church",21,31],["G1722","by",32,34],["G5547","Christ",35,41],["G2424","Jesus",42,47],["G1519","throughout",48,58],["G3956","all",59,62],["G1074","ages",63,67],["G0165","world",69,74],["G0165","without end",75,86],["G0281","Amen",88,92]]},"4:1":{"text":"I therefore, the prisoner of the Lord, beseech you that ye walk worthy of the vocation wherewith ye are called,","words":[["G1473","I",0,1],["G3767","therefore",2,11],["G1198","the prisoner",13,25],["G1722","of",26,28],["G2962","the Lord",29,37],["G3870","beseech",39,46],["G5209","you",47,50],["G4043","that ye walk",51,63],["G0516","worthy",64,70],["G2821","of the vocation",71,86],["G3739","wherewith",87,96],["G2564","ye are called",97,110]]},"4:2":{"text":"With all lowliness and meekness, with longsuffering, forbearing one another in love;","words":[["G3326","With",0,4],["G3956","all",5,8],["G5012","lowliness",9,18],["G2532","and",19,22],["G4236","meekness",23,31],["G3326","with",33,37],["G3115","longsuffering",38,51],["G0430","forbearing",53,63],["G0240","one another",64,75],["G1722","in",76,78],["G0026","love",79,83]]},"4:3":{"text":"Endeavouring to keep the unity of the Spirit in the bond of peace.","words":[["G4704","Endeavouring",0,12],["G5083","to keep",13,20],["G1775","the unity",21,30],["G4151","of the Spirit",31,44],["G1722","in",45,47],["G4886","the bond",48,56],["G1515","of peace",57,65]]},"4:4":{"text":"There is one body, and one Spirit, even as ye are called in one hope of your calling;","words":[["G1520","There is one",0,12],["G4983","body",13,17],["G2532","and",19,22],["G1520","one",23,26],["G4151","Spirit",27,33],["G2531","even as",35,42],["G2532","even as",35,42],["G2564","ye are called",43,56],["G1722","in",57,59],["G3391","one",60,63],["G1680","hope",64,68],["G5216","of your",69,76],["G2821","calling",77,84]]},"4:5":{"text":"One Lord, one faith, one baptism,","words":[["G1520","One",0,3],["G2962","Lord",4,8],["G1520","one",10,13],["G4102","faith",14,19],["G3391","one",21,24],["G0908","baptism",25,32]]},"4:6":{"text":"One God and Father of all, who is above all, and through all, and in you all.","words":[["G1520","One",0,3],["G2316","God",4,7],["G2532","and",8,11],["G3962","Father",12,18],["G3956","of all",19,25],["G3588","who",27,30],["G1909","is above",31,39],["G3956","all",40,43],["G2532","and",45,48],["G1223","through",49,56],["G3956","all",57,60],["G2532","and",62,65],["G1722","in",66,68],["G5213","you",69,72],["G3956","all",73,76]]},"4:7":{"text":"But unto every one of us is given grace according to the measure of the gift of Christ.","words":[["G1161","But",0,3],["G1538","unto every",4,14],["G1520","one",15,18],["G2257","of us",19,24],["G1325","is given",25,33],["G5485","grace",34,39],["G2596","according to",40,52],["G3358","the measure",53,64],["G1431","of the gift",65,76],["G5547","of Christ",77,86]]},"4:8":{"text":"Wherefore he saith, When he ascended up on high, he led captivity captive, and gave gifts unto men.","words":[["G1352","Wherefore",0,9],["G3004","he saith",10,18],["G0305","When he ascended",20,36],["G1519","up",37,39],["G5311","on high",40,47],["G0162","he led captivity",49,65],["G0161","captive",66,73],["G2532","and",75,78],["G1325","gave",79,83],["G1390","gifts",84,89],["G0444","unto men",90,98]]},"4:9":{"text":"(Now that he ascended, what is it but that he also descended first into the lower parts of the earth?","words":[["G1161","(Now",0,4],["G0305","that he ascended",5,21],["G5101","what",23,27],["G2076","is it",28,33],["G1508","but",34,37],["G3754","that",38,42],["G2597","he",43,45],["G2532","also",46,50],["G2597","descended",51,60],["G4412","first",61,66],["G1519","into",67,71],["G2737","the lower",72,81],["G3313","parts",82,87],["G1093","of the earth",88,100]]},"4:10":{"text":"He that descended is the same also that ascended up far above all heavens, that he might fill all things.)","words":[["G0846","He",0,2],["G2597","that descended",3,17],["G2076","is",18,20],["G2532","the same also",21,34],["G0305","that ascended up",35,51],["G5231","far above",52,61],["G3956","all",62,65],["G3772","heavens",66,73],["G2443","that",75,79],["G4137","he might fill",80,93],["G3956","all things",94,104]]},"4:11":{"text":"And he gave some, apostles; and some, prophets; and some, evangelists; and some, pastors and teachers;","words":[["G2532","And",0,3],["G0846","he",4,6],["G1325","gave",7,11],["G3303","some",12,16],["G0652","apostles",18,26],["G1161","and",28,31],["G4396","some, prophets",32,46],["G1161","and",48,51],["G2099","some, evangelists",52,69],["G1161","and",71,74],["G4166","some, pastors",75,88],["G2532","and",89,92],["G1320","teachers",93,101]]},"4:12":{"text":"For the perfecting of the saints, for the work of the ministry, for the edifying of the body of Christ:","words":[["G4314","For",0,3],["G2677","the perfecting",4,18],["G0040","of the saints",19,32],["G1519","for",34,37],["G2041","the work",38,46],["G1248","of the ministry",47,62],["G1519","for",64,67],["G3619","the edifying",68,80],["G4983","of the body",81,92],["G5547","of Christ",93,102]]},"4:13":{"text":"Till we all come in the unity of the faith, and of the knowledge of the Son of God, unto a perfect man, unto the measure of the stature of the fulness of Christ:","words":[["G3360","Till",0,4],["G3956","we all",5,11],["G2658","come",12,16],["G1519","in",17,19],["G1775","the unity",20,29],["G4102","of the faith",30,42],["G2532","and",44,47],["G1922","of the knowledge",48,64],["G5207","of the Son",65,75],["G2316","of God",76,82],["G1519","unto",84,88],["G5046","a perfect",89,98],["G0435","man",99,102],["G1519","unto",104,108],["G3358","the measure",109,120],["G2244","of the stature",121,135],["G4138","of the fulness",136,150],["G5547","of Christ",151,160]]},"4:14":{"text":"That we henceforth be no more children, tossed to and fro, and carried about with every wind of doctrine, by the sleight of men, and cunning craftiness, whereby they lie in wait to deceive;","words":[["G2443","That",0,4],["G5600","we henceforth be",5,21],["G3371","no more",22,29],["G3516","children",30,38],["G2831","tossed to and fro",40,57],["G2532","and",59,62],["G4064","carried about with",63,81],["G3956","every",82,87],["G0417","wind",88,92],["G1319","of doctrine",93,104],["G1722","by",106,108],["G2940","the sleight",109,120],["G0444","of men",121,127],["G1722","and cunning craftiness",129,151],["G3834","and cunning craftiness",129,151],["G4314","whereby",153,160],["G3180","they lie in wait",161,177],["G4106","to deceive",178,188]]},"4:15":{"text":"But speaking the truth in love, may grow up into him in all things, which is the head, even Christ:","words":[["G1161","But",0,3],["G0226","speaking the truth",4,22],["G1722","in",23,25],["G0026","love",26,30],["G0837","may grow up",32,43],["G1519","into",44,48],["G0846","him",49,52],["G3956","in all things",53,66],["G3739","which",68,73],["G2076","is",74,76],["G2776","the head",77,85],["G5547","even Christ",87,98]]},"4:16":{"text":"From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh increase of the body unto the edifying of itself in love.","words":[["G1537","From",0,4],["G3739","whom",5,9],["G3956","the whole",10,19],["G4983","body",20,24],["G4883","fitly joined together",25,46],["G2532","and",47,50],["G4822","compacted",51,60],["G1223","by",61,63],["G3956","that which every",64,80],["G0860","joint",81,86],["G2024","supplieth",87,96],["G2596","according",98,107],["G1753","to the effectual working",108,132],["G1722","in",133,135],["G3358","the measure",136,147],["G1538","of every",148,156],["G1520","part",157,161],["G3313","part",157,161],["G4160","maketh",163,169],["G0838","increase",170,178],["G4983","of the body",179,190],["G1519","unto",191,195],["G3619","the edifying",196,208],["G1438","of itself",209,218],["G1722","in",219,221],["G0026","love",222,226]]},"4:17":{"text":"This I say therefore, and testify in the Lord, that ye henceforth walk not as other Gentiles walk, in the vanity of their mind,","words":[["G5124","This",0,4],["G3004","I say",5,10],["G3767","therefore",11,20],["G2532","and",22,25],["G3143","testify",26,33],["G1722","in",34,36],["G2962","the Lord",37,45],["G5209","that ye",47,54],["G3371","henceforth",55,65],["G4043","walk",66,70],["G3371","not",71,74],["G2531","as",75,77],["G2532","as",75,77],["G3062","other",78,83],["G1484","Gentiles",84,92],["G4043","walk",93,97],["G1722","in",99,101],["G3153","the vanity",102,112],["G0846","of their",113,121],["G3563","mind",122,126]]},"4:18":{"text":"Having the understanding darkened, being alienated from the life of God through the ignorance that is in them, because of the blindness of their heart:","words":[["G1271","Having the understanding",0,24],["G4654","darkened",25,33],["G5607","being",35,40],["G0526","alienated",41,50],["G2222","from the life",51,64],["G2316","of God",65,71],["G1223","through",72,79],["G0052","the ignorance",80,93],["G5607","that is",94,101],["G1722","in",102,104],["G0846","them",105,109],["G1223","because",111,118],["G4457","of the blindness",119,135],["G0846","of their",136,144],["G2588","heart",145,150]]},"4:19":{"text":"Who being past feeling have given themselves over unto lasciviousness, to work all uncleanness with greediness.","words":[["G3748","Who",0,3],["G0524","being past feeling",4,22],["G3860","have given",23,33],["G1438","themselves",34,44],["G3860","over",45,49],["G0766","unto lasciviousness",50,69],["G1519","to",71,73],["G2039","work",74,78],["G3956","all",79,82],["G0167","uncleanness",83,94],["G1722","with",95,99],["G4124","greediness",100,110]]},"4:20":{"text":"But ye have not so learned Christ;","words":[["G1161","But",0,3],["G5210","ye",4,6],["G3129","have",7,11],["G3756","not",12,15],["G3779","so",16,18],["G3129","learned",19,26],["G5547","Christ",27,33]]},"4:21":{"text":"If so be that ye have heard him, and have been taught by him, as the truth is in Jesus:","words":[["G1489","If so be that",0,13],["G0191","ye have heard",14,27],["G0846","him",28,31],["G2532","and",33,36],["G1321","have been taught",37,53],["G1722","by",54,56],["G0846","him",57,60],["G2531","as",62,64],["G0225","the truth",65,74],["G2076","is",75,77],["G1722","in",78,80],["G2424","Jesus",81,86]]},"4:22":{"text":"That ye put off concerning the former conversation the old man, which is corrupt according to the deceitful lusts;","words":[["G5209","That ye",0,7],["G0659","put off",8,15],["G2596","concerning",16,26],["G4387","the former",27,37],["G0391","conversation",38,50],["G3820","the old",51,58],["G0444","man",59,62],["G3588","which",64,69],["G5351","is corrupt",70,80],["G2596","according",81,90],["G0539","to the deceitful",91,107],["G1939","lusts",108,113]]},"4:23":{"text":"And be renewed in the spirit of your mind;","words":[["G1161","And",0,3],["G0365","be renewed",4,14],["G4151","in the spirit",15,28],["G5216","of your",29,36],["G3563","mind",37,41]]},"4:24":{"text":"And that ye put on the new man, which after God is created in righteousness and true holiness.","words":[["G2532","And",0,3],["G1746","that ye put on",4,18],["G2537","the new",19,26],["G0444","man",27,30],["G3588","which",32,37],["G2596","after",38,43],["G2316","God",44,47],["G2936","is created",48,58],["G1722","in",59,61],["G1343","righteousness",62,75],["G2532","and",76,79],["G0225","true",80,84],["G3742","holiness",85,93]]},"4:25":{"text":"Wherefore putting away lying, speak every man truth with his neighbour: for we are members one of another.","words":[["G1352","Wherefore",0,9],["G0659","putting away",10,22],["G5579","lying",23,28],["G2980","speak",30,35],["G1538","every man",36,45],["G0225","truth",46,51],["G3326","with",52,56],["G0846","his",57,60],["G4139","neighbour",61,70],["G3754","for",72,75],["G2070","we are",76,82],["G3196","members",83,90],["G0240","one of another",91,105]]},"4:26":{"text":"Be ye angry, and sin not: let not the sun go down upon your wrath:","words":[["G3710","Be ye angry",0,11],["G2532","and",13,16],["G0264","sin",17,20],["G3361","not",21,24],["G1931","let",26,29],["G3361","not",30,33],["G2246","the sun",34,41],["G1931","go down",42,49],["G1909","upon",50,54],["G5216","your",55,59],["G3950","wrath",60,65]]},"4:27":{"text":"Neither give place to the devil.","words":[["G3383","Neither",0,7],["G1325","give",8,12],["G5117","place",13,18],["G1228","to the devil",19,31]]},"4:28":{"text":"Let him that stole steal no more: but rather let him labour, working with his hands the thing which is good, that he may have to give to him that needeth.","words":[["G2813","Let",0,3],["G2813","him that stole",4,18],["G2813","steal",19,24],["G3371","no more",25,32],["G1161","but",34,37],["G3123","rather",38,44],["G2872","let him labour",45,59],["G2038","working",61,68],["G5495","with his hands",69,83],["G0018","the thing which is good",84,107],["G2443","that",109,113],["G2192","he may have",114,125],["G3330","to give",126,133],["G5532","to him that needeth",134,153],["G2192","to him that needeth",134,153]]},"4:29":{"text":"Let no corrupt communication proceed out of your mouth, but that which is good to the use of edifying, that it may minister grace unto the hearers.","words":[["G4550","Let",0,3],["G3361","no",4,6],["G3956","no",4,6],["G4550","corrupt",7,14],["G3056","communication",15,28],["G1607","proceed",29,36],["G1537","out of",37,43],["G5216","your",44,48],["G4750","mouth",49,54],["G0235","but",56,59],["G1536","that which",60,70],["G0018","is good",71,78],["G4314","to",79,81],["G5532","the use",82,89],["G3619","of edifying",90,101],["G2443","that",103,107],["G1325","it may minister",108,123],["G5485","grace",124,129],["G0191","unto the hearers",130,146]]},"4:30":{"text":"And grieve not the holy Spirit of God, whereby ye are sealed unto the day of redemption.","words":[["G2532","And",0,3],["G3076","grieve",4,10],["G3361","not",11,14],["G0040","the holy",15,23],["G4151","Spirit",24,30],["G2316","of God",31,37],["G1722","whereby",39,46],["G3739","whereby",39,46],["G4972","ye are sealed",47,60],["G1519","unto",61,65],["G2250","the day",66,73],["G0629","of redemption",74,87]]},"4:31":{"text":"Let all bitterness, and wrath, and anger, and clamour, and evil speaking, be put away from you, with all malice:","words":[["G0142","Let",0,3],["G3956","all",4,7],["G4088","bitterness",8,18],["G2532","and",20,23],["G2372","wrath",24,29],["G2532","and",31,34],["G3709","anger",35,40],["G2532","and",42,45],["G2906","clamour",46,53],["G2532","and",55,58],["G0988","evil speaking",59,72],["G0142","be put away",74,85],["G0575","from",86,90],["G5216","you",91,94],["G4862","with",96,100],["G3956","all",101,104],["G2549","malice",105,111]]},"4:32":{"text":"And be ye kind one to another, tenderhearted, forgiving one another, even as God for Christ's sake hath forgiven you.","words":[["G1161","And",0,3],["G1096","be",4,6],["G5543","ye kind",7,14],["G1519","one to another",15,29],["G0240","one to another",15,29],["G2155","tenderhearted",31,44],["G5483","forgiving",46,55],["G1438","one another",56,67],["G2531","even as",69,76],["G2532","even as",69,76],["G2316","God",77,80],["G1722","for",81,84],["G5547","Christ's",85,93],["G1722","sake",94,98],["G5483","hath forgiven",99,112],["G5213","you",113,116]]},"5:1":{"text":"Be ye therefore followers of God, as dear children;","words":[["G1096","Be",0,2],["G3402","ye",3,5],["G3767","therefore",6,15],["G3402","followers",16,25],["G2316","of God",26,32],["G5613","as",34,36],["G0027","dear",37,41],["G5043","children",42,50]]},"5:2":{"text":"And walk in love, as Christ also hath loved us, and hath given himself for us an offering and a sacrifice to God for a sweetsmelling savour.","words":[["G2532","And",0,3],["G4043","walk",4,8],["G1722","in",9,11],["G0026","love",12,16],["G2531","as",18,20],["G5547","Christ",21,27],["G2532","also",28,32],["G0025","hath loved",33,43],["G2248","us",44,46],["G2532","and",48,51],["G3860","hath given",52,62],["G1438","himself",63,70],["G5228","for",71,74],["G2257","us",75,77],["G4376","an offering",78,89],["G2532","and",90,93],["G2378","a sacrifice",94,105],["G2316","to God",106,112],["G1519","for",113,116],["G2175","a sweetsmelling",117,132],["G3744","savour",133,139]]},"5:3":{"text":"But fornication, and all uncleanness, or covetousness, let it not be once named among you, as becometh saints;","words":[["G2532","But",0,3],["G4202","fornication",4,15],["G1161","and",17,20],["G3956","all",21,24],["G0167","uncleanness",25,36],["G2228","or",38,40],["G4124","covetousness",41,53],["G3687","let it",55,61],["G3366","not be once",62,73],["G3687","named",74,79],["G1722","among",80,85],["G5213","you",86,89],["G2531","as",91,93],["G4241","becometh",94,102],["G0040","saints",103,109]]},"5:4":{"text":"Neither filthiness, nor foolish talking, nor jesting, which are not convenient: but rather giving of thanks.","words":[["G2532","Neither",0,7],["G0151","filthiness",8,18],["G2532","nor",20,23],["G3473","foolish talking",24,39],["G2228","nor",41,44],["G2160","jesting",45,52],["G3588","which",54,59],["G0433","are",60,63],["G3756","not",64,67],["G0433","convenient",68,78],["G0235","but",80,83],["G3123","rather",84,90],["G2169","giving of thanks",91,107]]},"5:5":{"text":"For this ye know, that no whoremonger, nor unclean person, nor covetous man, who is an idolater, hath any inheritance in the kingdom of Christ and of God.","words":[["G1063","For",0,3],["G5124","this",4,8],["G2075","ye know",9,16],["G1097","ye know",9,16],["G3754","that",18,22],["G3756","no",23,25],["G3956","no",23,25],["G4205","whoremonger",26,37],["G2228","nor",39,42],["G0169","unclean person",43,57],["G2228","nor",59,62],["G4123","covetous man",63,75],["G3739","who",77,80],["G2076","is",81,83],["G1496","an idolater",84,95],["G2192","hath",97,101],["G2817","any inheritance",102,117],["G1722","in",118,120],["G0932","the kingdom",121,132],["G5547","of Christ",133,142],["G2532","and",143,146],["G2316","of God",147,153]]},"5:6":{"text":"Let no man deceive you with vain words: for because of these things cometh the wrath of God upon the children of disobedience.","words":[["G0538","Let",0,3],["G3367","no man",4,10],["G0538","deceive",11,18],["G5209","you",19,22],["G2756","with vain",23,32],["G3056","words",33,38],["G1063","for",40,43],["G1223","because",44,51],["G5023","of these things",52,67],["G2064","cometh",68,74],["G3709","the wrath",75,84],["G2316","of God",85,91],["G1909","upon",92,96],["G5207","the children",97,109],["G0543","of disobedience",110,125]]},"5:7":{"text":"Be not ye therefore partakers with them.","words":[["G1096","Be",0,2],["G3361","not",3,6],["G1096","ye",7,9],["G3767","therefore",10,19],["G4830","partakers",20,29],["G0846","with them",30,39]]},"5:8":{"text":"For ye were sometimes darkness, but now are ye light in the Lord: walk as children of light:","words":[["G1063","For",0,3],["G2258","ye were",4,11],["G4218","sometimes",12,21],["G4655","darkness",22,30],["G1161","but",32,35],["G3568","now",36,39],["G5457","are ye light",40,52],["G1722","in",53,55],["G2962","the Lord",56,64],["G4043","walk",66,70],["G5613","as",71,73],["G5043","children",74,82],["G5457","of light",83,91]]},"5:9":{"text":"(For the fruit of the Spirit is in all goodness and righteousness and truth;)","words":[["G1063","(For",0,4],["G2590","the fruit",5,14],["G4151","of the Spirit",15,28],["G1722","is in",29,34],["G3956","all",35,38],["G0019","goodness",39,47],["G2532","and",48,51],["G1343","righteousness",52,65],["G2532","and",66,69],["G0225","truth",70,75]]},"5:10":{"text":"Proving what is acceptable unto the Lord.","words":[["G1381","Proving",0,7],["G5101","what",8,12],["G2076","is",13,15],["G2101","acceptable",16,26],["G2962","unto the Lord",27,40]]},"5:11":{"text":"And have no fellowship with the unfruitful works of darkness, but rather reprove them.","words":[["G2532","And",0,3],["G4790","have",4,8],["G3361","no",9,11],["G4790","fellowship",12,22],["G0175","with the unfruitful",23,42],["G2041","works",43,48],["G4655","of darkness",49,60],["G1161","but",62,65],["G3123","rather",66,72],["G2532","rather",66,72],["G1651","reprove",73,80]]},"5:12":{"text":"For it is a shame even to speak of those things which are done of them in secret.","words":[["G1063","For",0,3],["G2076","it is",4,9],["G0149","a shame",10,17],["G2532","even",18,22],["G3004","to speak",23,31],["G2931","of those things",32,47],["G1096","which are done",48,62],["G5259","of",63,65],["G0846","them",66,70],["G2931","in secret",71,80]]},"5:13":{"text":"But all things that are reproved are made manifest by the light: for whatsoever doth make manifest is light.","words":[["G1161","But",0,3],["G3956","all things",4,14],["G1651","that are reproved",15,32],["G5319","are made manifest",33,50],["G5259","by",51,53],["G5457","the light",54,63],["G1063","for",65,68],["G3956","whatsoever",69,79],["G5319","doth make manifest",80,98],["G2076","is",99,101],["G5457","light",102,107]]},"5:14":{"text":"Wherefore he saith, Awake thou that sleepest, and arise from the dead, and Christ shall give thee light.","words":[["G1352","Wherefore",0,9],["G3004","he saith",10,18],["G1453","Awake thou",20,30],["G2518","that sleepest",31,44],["G2532","and",46,49],["G0450","arise",50,55],["G1537","from",56,60],["G3498","the dead",61,69],["G2532","and",71,74],["G5547","Christ",75,81],["G2017","shall give",82,92],["G4671","thee",93,97],["G2017","light",98,103]]},"5:15":{"text":"See then that ye walk circumspectly, not as fools, but as wise,","words":[["G0991","See",0,3],["G3767","then",4,8],["G4459","that",9,13],["G4043","ye walk",14,21],["G0199","circumspectly",22,35],["G3361","not",37,40],["G5613","as",41,43],["G0781","fools",44,49],["G0235","but",51,54],["G5613","as",55,57],["G4680","wise",58,62]]},"5:16":{"text":"Redeeming the time, because the days are evil.","words":[["G1805","Redeeming",0,9],["G2540","the time",10,18],["G3754","because",20,27],["G2250","the days",28,36],["G1526","are",37,40],["G4190","evil",41,45]]},"5:17":{"text":"Wherefore be ye not unwise, but understanding what the will of the Lord is.","words":[["G1223","Wherefore",0,9],["G5124","Wherefore",0,9],["G1096","be ye",10,15],["G3361","not",16,19],["G0878","unwise",20,26],["G0235","but",28,31],["G4920","understanding",32,45],["G5101","what",46,50],["G2307","the will",51,59],["G2962","of the Lord",60,71]]},"5:18":{"text":"And be not drunk with wine, wherein is excess; but be filled with the Spirit;","words":[["G2532","And",0,3],["G3182","be",4,6],["G3361","not",7,10],["G3182","drunk",11,16],["G3631","with wine",17,26],["G1722","wherein",28,35],["G3739","wherein",28,35],["G2076","is",36,38],["G0810","excess",39,45],["G0235","but",47,50],["G4137","be filled",51,60],["G1722","with",61,65],["G4151","the Spirit",66,76]]},"5:19":{"text":"Speaking to yourselves in psalms and hymns and spiritual songs, singing and making melody in your heart to the Lord;","words":[["G2980","Speaking",0,8],["G1438","to yourselves",9,22],["G5568","in psalms",23,32],["G2532","and",33,36],["G5215","hymns",37,42],["G2532","and",43,46],["G4152","spiritual",47,56],["G5603","songs",57,62],["G0103","singing",64,71],["G2532","and",72,75],["G5567","making melody",76,89],["G1722","in",90,92],["G5216","your",93,97],["G2588","heart",98,103],["G2962","to the Lord",104,115]]},"5:20":{"text":"Giving thanks always for all things unto God and the Father in the name of our Lord Jesus Christ;","words":[["G2168","Giving thanks",0,13],["G3842","always",14,20],["G5228","for",21,24],["G3956","all things",25,35],["G2316","unto God",36,44],["G2532","and",45,48],["G3962","the Father",49,59],["G1722","in",60,62],["G3686","the name",63,71],["G2257","of our",72,78],["G2962","Lord",79,83],["G2424","Jesus",84,89],["G5547","Christ",90,96]]},"5:21":{"text":"Submitting yourselves one to another in the fear of God.","words":[["G5293","Submitting yourselves",0,21],["G0240","one to another",22,36],["G1722","in",37,39],["G5401","the fear",40,48],["G2316","of God",49,55]]},"5:22":{"text":"Wives, submit yourselves unto your own husbands, as unto the Lord.","words":[["G1135","Wives",0,5],["G5293","submit yourselves",7,24],["G2398","unto your own",25,38],["G0435","husbands",39,47],["G5613","as",49,51],["G2962","unto the Lord",52,65]]},"5:23":{"text":"For the husband is the head of the wife, even as Christ is the head of the church: and he is the saviour of the body.","words":[["G3754","For",0,3],["G0435","the husband",4,15],["G2076","is",16,18],["G2776","the head",19,27],["G1135","of the wife",28,39],["G2532","even",41,45],["G5613","as",46,48],["G5547","Christ",49,55],["G2776","is the head",56,67],["G1577","of the church",68,81],["G2532","and",83,86],["G0846","he",87,89],["G2076","is",90,92],["G4990","the saviour",93,104],["G4983","of the body",105,116]]},"5:24":{"text":"Therefore as the church is subject unto Christ, so let the wives be to their own husbands in every thing.","words":[["G0235","Therefore",0,9],["G5618","as",10,12],["G1577","the church",13,23],["G5293","is subject",24,34],["G5547","unto Christ",35,46],["G3779","so",48,50],["G2532","so",48,50],["G1135","let the wives",51,64],["G2398","be to their own",65,80],["G0435","husbands",81,89],["G1722","in",90,92],["G3956","every thing",93,104]]},"5:25":{"text":"Husbands, love your wives, even as Christ also loved the church, and gave himself for it;","words":[["G0435","Husbands",0,8],["G0025","love",10,14],["G1438","your",15,19],["G1135","wives",20,25],["G2531","even as",27,34],["G5547","Christ",35,41],["G2532","also",42,46],["G0025","loved",47,52],["G1577","the church",53,63],["G2532","and",65,68],["G3860","gave",69,73],["G1438","himself",74,81],["G5228","for",82,85],["G0846","it",86,88]]},"5:26":{"text":"That he might sanctify and cleanse it with the washing of water by the word,","words":[["G2443","That",0,4],["G0846","he",5,7],["G0037","might sanctify",8,22],["G2511","and cleanse it",23,37],["G3067","with the washing",38,54],["G5204","of water",55,63],["G1722","by",64,66],["G4487","the word",67,75]]},"5:27":{"text":"That he might present it to himself a glorious church, not having spot, or wrinkle, or any such thing; but that it should be holy and without blemish.","words":[["G2443","That",0,4],["G3936","he might present",5,21],["G0846","it",22,24],["G1438","to himself",25,35],["G1741","a glorious",36,46],["G1577","church",47,53],["G3361","not",55,58],["G2192","having",59,65],["G4696","spot",66,70],["G2228","or",72,74],["G4512","wrinkle",75,82],["G2228","or",84,86],["G5100","any",87,90],["G5108","such thing",91,101],["G0235","but",103,106],["G2443","that",107,111],["G5600","it should be",112,124],["G0040","holy",125,129],["G2532","and",130,133],["G0299","without blemish",134,149]]},"5:28":{"text":"So ought men to love their wives as their own bodies. He that loveth his wife loveth himself.","words":[["G3779","So",0,2],["G3784","ought",3,8],["G0435","men",9,12],["G0025","to love",13,20],["G1438","their",21,26],["G1135","wives",27,32],["G5613","as",33,35],["G1438","their own",36,45],["G4983","bodies",46,52],["G0025","He that loveth",54,68],["G1438","his",69,72],["G1135","wife",73,77],["G0025","loveth",78,84],["G1438","himself",85,92]]},"5:29":{"text":"For no man ever yet hated his own flesh; but nourisheth and cherisheth it, even as the Lord the church:","words":[["G1063","For",0,3],["G3762","no man",4,10],["G4218","ever yet",11,19],["G3404","hated",20,25],["G1438","his own",26,33],["G4561","flesh",34,39],["G0235","but",41,44],["G1625","nourisheth",45,55],["G2532","and",56,59],["G2282","cherisheth",60,70],["G0846","it",71,73],["G2531","even as",75,82],["G2532","even as",75,82],["G2962","the Lord",83,91],["G1577","the church",92,102]]},"5:30":{"text":"For we are members of his body, of his flesh, and of his bones.","words":[["G3754","For",0,3],["G2070","we are",4,10],["G3196","members",11,18],["G0846","of his",19,25],["G4983","body",26,30],["G1537","of",32,34],["G0846","his",35,38],["G4561","flesh",39,44],["G2532","and",46,49],["G1537","of",50,52],["G0846","his",53,56],["G3747","bones",57,62]]},"5:31":{"text":"For this cause shall a man leave his father and mother, and shall be joined unto his wife, and they two shall be one flesh.","words":[["G0473","For",0,3],["G5127","this cause",4,14],["G2641","shall",15,20],["G0444","a man",21,26],["G2641","leave",27,32],["G0846","his",33,36],["G3962","father",37,43],["G2532","and",44,47],["G3384","mother",48,54],["G2532","and",56,59],["G4347","shall be joined",60,75],["G4314","unto",76,80],["G0846","his",81,84],["G1135","wife",85,89],["G2532","and",91,94],["G1417","they two",95,103],["G2071","shall be",104,112],["G1519","one",113,116],["G3391","one",113,116],["G4561","flesh",117,122]]},"5:32":{"text":"This is a great mystery: but I speak concerning Christ and the church.","words":[["G5124","This",0,4],["G2076","is",5,7],["G3173","a great",8,15],["G3466","mystery",16,23],["G1161","but",25,28],["G1473","I",29,30],["G3004","speak",31,36],["G1519","concerning",37,47],["G5547","Christ",48,54],["G1519","and",55,58],["G2532","and",55,58],["G1577","the church",59,69]]},"5:33":{"text":"Nevertheless let every one of you in particular so love his wife even as himself; and the wife see that she reverence her husband.","words":[["G4133","Nevertheless",0,12],["G2532","Nevertheless",0,12],["G0025","let",13,16],["G1520","every one",17,26],["G1538","every one",17,26],["G5210","of you",27,33],["G2596","in particular",34,47],["G3779","so",48,50],["G0025","love",51,55],["G1438","his",56,59],["G1135","wife",60,64],["G5613","even as",65,72],["G1438","himself",73,80],["G1161","and",82,85],["G1135","the wife",86,94],["G2443","see that",95,103],["G5399","she reverence",104,117],["G0435","her husband",118,129]]},"6:1":{"text":"Children, obey your parents in the Lord: for this is right.","words":[["G5043","Children",0,8],["G5219","obey",10,14],["G5216","your",15,19],["G1118","parents",20,27],["G1722","in",28,30],["G2962","the Lord",31,39],["G1063","for",41,44],["G5124","this",45,49],["G2076","is",50,52],["G1342","right",53,58]]},"6:2":{"text":"Honour thy father and mother; (which is the first commandment with promise;)","words":[["G5091","Honour",0,6],["G4675","thy",7,10],["G3962","father",11,17],["G2532","and",18,21],["G3384","mother",22,28],["G3748","(which",30,36],["G2076","is",37,39],["G4413","the first",40,49],["G1785","commandment",50,61],["G1722","with",62,66],["G1860","promise",67,74]]},"6:3":{"text":"That it may be well with thee, and thou mayest live long on the earth.","words":[["G2443","That",0,4],["G1096","it may be",5,14],["G2095","well",15,19],["G4671","with thee",20,29],["G2532","and",31,34],["G2071","thou mayest",35,46],["G3118","live long",47,56],["G1909","on",57,59],["G1093","the earth",60,69]]},"6:4":{"text":"And, ye fathers, provoke not your children to wrath: but bring them up in the nurture and admonition of the Lord.","words":[["G2532","And",0,3],["G3962","ye fathers",5,15],["G3949","provoke",17,24],["G3361","not",25,28],["G5216","your",29,33],["G5043","children",34,42],["G3949","to wrath",43,51],["G0235","but",53,56],["G1625","bring",57,62],["G0846","them",63,67],["G1625","up",68,70],["G1722","in",71,73],["G3809","the nurture",74,85],["G2532","and",86,89],["G3559","admonition",90,100],["G2962","of the Lord",101,112]]},"6:5":{"text":"Servants, be obedient to them that are your masters according to the flesh, with fear and trembling, in singleness of your heart, as unto Christ;","words":[["G1401","Servants",0,8],["G5219","be obedient",10,21],["G2962","to them that are your masters",22,51],["G2596","according to",52,64],["G4561","the flesh",65,74],["G3326","with",76,80],["G5401","fear",81,85],["G2532","and",86,89],["G5156","trembling",90,99],["G1722","in",101,103],["G0572","singleness",104,114],["G5216","of your",115,122],["G2588","heart",123,128],["G5613","as",130,132],["G5547","unto Christ",133,144]]},"6:6":{"text":"Not with eyeservice, as menpleasers; but as the servants of Christ, doing the will of God from the heart;","words":[["G3361","Not",0,3],["G2596","with",4,8],["G3787","eyeservice",9,19],["G5613","as",21,23],["G0441","menpleasers",24,35],["G0235","but",37,40],["G5613","as",41,43],["G1401","the servants",44,56],["G5547","of Christ",57,66],["G4160","doing",68,73],["G2307","the will",74,82],["G2316","of God",83,89],["G1537","from",90,94],["G5590","the heart",95,104]]},"6:7":{"text":"With good will doing service, as to the Lord, and not to men:","words":[["G3326","With",0,4],["G2133","good will",5,14],["G1398","doing service",15,28],["G2962","as to the Lord",30,44],["G2532","and",46,49],["G3756","not",50,53],["G0444","to men",54,60]]},"6:8":{"text":"Knowing that whatsoever good thing any man doeth, the same shall he receive of the Lord, whether he be bond or free.","words":[["G1492","Knowing",0,7],["G3754","that",8,12],["G3739","whatsoever",13,23],["G1437","whatsoever",13,23],["G5100","whatsoever",13,23],["G0018","good thing",24,34],["G1538","any man",35,42],["G4160","doeth",43,48],["G5124","the same",50,58],["G2865","shall he receive",59,75],["G3844","of",76,78],["G2962","the Lord",79,87],["G1535","whether",89,96],["G1401","he be bond",97,107],["G1535","or",108,110],["G1658","free",111,115]]},"6:9":{"text":"And, ye masters, do the same things unto them, forbearing threatening: knowing that your Master also is in heaven; neither is there respect of persons with him.","words":[["G2532","And",0,3],["G2962","ye masters",5,15],["G4160","do",17,19],["G0846","the same things",20,35],["G4314","unto",36,40],["G0846","them",41,45],["G0447","forbearing",47,57],["G0547","threatening",58,69],["G1492","knowing",71,78],["G3754","that",79,83],["G5216","your",84,88],["G0846","your",84,88],["G2962","Master",89,95],["G2532","also",96,100],["G2076","is",101,103],["G1722","in",104,106],["G3772","heaven",107,113],["G2532","neither",115,122],["G3756","neither",115,122],["G2076","is there",123,131],["G4382","respect of persons",132,150],["G3844","with",151,155],["G0846","him",156,159]]},"6:10":{"text":"Finally, my brethren, be strong in the Lord, and in the power of his might.","words":[["G3063","Finally",0,7],["G3450","my",9,11],["G0080","brethren",12,20],["G1743","be strong",22,31],["G1722","in",32,34],["G2962","the Lord",35,43],["G2532","and",45,48],["G1722","in",49,51],["G2904","the power",52,61],["G0846","of his",62,68],["G2479","might",69,74]]},"6:11":{"text":"Put on the whole armour of God, that ye may be able to stand against the wiles of the devil.","words":[["G1746","Put on",0,6],["G3833","the whole armour",7,23],["G2316","of God",24,30],["G4314","that",32,36],["G5209","ye",37,39],["G1410","may be able",40,51],["G2476","to stand",52,60],["G4314","against",61,68],["G3180","the wiles",69,78],["G1228","of the devil",79,91]]},"6:12":{"text":"For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness in high places.","words":[["G3754","For",0,3],["G2254","we",4,6],["G3823","wrestle",7,14],["G3756","not",15,18],["G2076","against",19,26],["G4314","against",19,26],["G4561","flesh",27,32],["G2532","and",33,36],["G0129","blood",37,42],["G0235","but",44,47],["G4314","against",48,55],["G0746","principalities",56,70],["G4314","against",72,79],["G1849","powers",80,86],["G4314","against",88,95],["G2888","the rulers",96,106],["G4655","of the darkness",107,122],["G5127","of this",123,130],["G0165","world",131,136],["G4314","against",138,145],["G4152","spiritual",146,155],["G4189","wickedness",156,166],["G1722","in",167,169],["G2032","high",170,174]]},"6:13":{"text":"Wherefore take unto you the whole armour of God, that ye may be able to withstand in the evil day, and having done all, to stand.","words":[["G1223","Wherefore",0,9],["G5124","Wherefore",0,9],["G0353","take unto you",10,23],["G3833","the whole armour",24,40],["G2316","of God",41,47],["G2443","that",49,53],["G1410","ye may be able",54,68],["G0436","to withstand",69,81],["G1722","in",82,84],["G4190","the evil",85,93],["G2250","day",94,97],["G2532","and",99,102],["G2716","having done",103,114],["G0537","all",115,118],["G2476","to stand",120,128]]},"6:14":{"text":"Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness;","words":[["G2476","Stand",0,5],["G3767","therefore",6,15],["G4024","having",17,23],["G5216","your",24,28],["G3751","loins",29,34],["G4024","girt about",35,45],["G1722","with",46,50],["G0225","truth",51,56],["G2532","and",58,61],["G1746","having on",62,71],["G2382","the breastplate",72,87],["G1343","of righteousness",88,104]]},"6:15":{"text":"And your feet shod with the preparation of the gospel of peace;","words":[["G2532","And",0,3],["G4228","your feet",4,13],["G5265","shod",14,18],["G1722","with",19,23],["G2091","the preparation",24,39],["G2098","of the gospel",40,53],["G1515","of peace",54,62]]},"6:16":{"text":"Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked.","words":[["G1909","Above",0,5],["G3956","all",6,9],["G0353","taking",11,17],["G2375","the shield",18,28],["G4102","of faith",29,37],["G1722","wherewith",39,48],["G3739","wherewith",39,48],["G1410","ye shall be able",49,65],["G4570","to quench",66,75],["G3956","all",76,79],["G4448","the fiery",80,89],["G0956","darts",90,95],["G4190","of the wicked",96,109]]},"6:17":{"text":"And take the helmet of salvation, and the sword of the Spirit, which is the word of God:","words":[["G2532","And",0,3],["G1209","take",4,8],["G4030","the helmet",9,19],["G4992","of salvation",20,32],["G2532","and",34,37],["G3162","the sword",38,47],["G4151","of the Spirit",48,61],["G3603","which is",63,71],["G4487","the word",72,80],["G2316","of God",81,87]]},"6:18":{"text":"Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication for all saints;","words":[["G4336","Praying",0,7],["G1722","always",8,14],["G2540","always",8,14],["G3956","always",8,14],["G1223","with",15,19],["G3956","all",20,23],["G4335","prayer",24,30],["G2532","and",31,34],["G1162","supplication",35,47],["G1722","in",48,50],["G4151","the Spirit",51,61],["G2532","and",63,66],["G0069","watching",67,75],["G1519","thereunto",76,85],["G5124","thereunto",76,85],["G0846","thereunto",76,85],["G1722","with",86,90],["G3956","all",91,94],["G4343","perseverance",95,107],["G2532","and",108,111],["G1162","supplication",112,124],["G4012","for",125,128],["G3956","all",129,132],["G0040","saints",133,139]]},"6:19":{"text":"And for me, that utterance may be given unto me, that I may open my mouth boldly, to make known the mystery of the gospel,","words":[["G2532","And",0,3],["G5228","for",4,7],["G1700","me",8,10],["G2443","that",12,16],["G3056","utterance",17,26],["G1325","may be given",27,39],["G3427","unto me",40,47],["G1722","that I may open",49,64],["G0457","that I may open",49,64],["G3450","my",65,67],["G4750","mouth",68,73],["G1722","boldly",74,80],["G3954","boldly",74,80],["G1107","to make known",82,95],["G3466","the mystery",96,107],["G2098","of the gospel",108,121]]},"6:20":{"text":"For which I am an ambassador in bonds: that therein I may speak boldly, as I ought to speak.","words":[["G5228","For",0,3],["G3739","which",4,9],["G4243","I am an ambassador",10,28],["G1722","in",29,31],["G0254","bonds",32,37],["G2443","that",39,43],["G1722","therein",44,51],["G0846","therein",44,51],["G3955","I may speak boldly",52,70],["G5613","as",72,74],["G3165","I",75,76],["G1163","ought",77,82],["G2980","to speak",83,91]]},"6:21":{"text":"But that ye also may know my affairs, and how I do, Tychicus, a beloved brother and faithful minister in the Lord, shall make known to you all things:","words":[["G1161","But",0,3],["G2443","that",4,8],["G5210","ye",9,11],["G2532","also",12,16],["G1492","may know",17,25],["G1691","my",26,28],["G2596","affairs",29,36],["G5101","and how",38,45],["G4238","I do",46,50],["G5190","Tychicus",52,60],["G0027","a beloved",62,71],["G0080","brother",72,79],["G2532","and",80,83],["G4103","faithful",84,92],["G1249","minister",93,101],["G1722","in",102,104],["G2962","the Lord",105,113],["G1107","shall make known",115,131],["G5213","to you",132,138],["G3956","all things",139,149]]},"6:22":{"text":"Whom I have sent unto you for the same purpose, that ye might know our affairs, and that he might comfort your hearts.","words":[["G3739","Whom",0,4],["G3992","I have sent",5,16],["G4314","unto",17,21],["G5209","you",22,25],["G1519","for",26,29],["G0846","the same",30,38],["G5124","purpose",39,46],["G2443","that",48,52],["G1097","ye might know",53,66],["G2257","our",67,70],["G4012","affairs",71,78],["G2532","and",80,83],["G3870","that he might comfort",84,105],["G5216","your",106,110],["G2588","hearts",111,117]]},"6:23":{"text":"Peace be to the brethren, and love with faith, from God the Father and the Lord Jesus Christ.","words":[["G1515","Peace",0,5],["G0080","be to the brethren",6,24],["G2532","and",26,29],["G0026","love",30,34],["G3326","with",35,39],["G4102","faith",40,45],["G0575","from",47,51],["G2316","God",52,55],["G3962","the Father",56,66],["G2532","and",67,70],["G2962","the Lord",71,79],["G2424","Jesus",80,85],["G5547","Christ",86,92]]},"6:24":{"text":"Grace be with all them that love our Lord Jesus Christ in sincerity. Amen.","words":[["G5485","Grace",0,5],["G3326","be with",6,13],["G3956","all",14,17],["G0025","them that love",18,32],["G2257","our",33,36],["G2962","Lord",37,41],["G2424","Jesus",42,47],["G5547","Christ",48,54],["G1722","in",55,57],["G0861","sincerity",58,67],["G0281","Amen",69,73]]}}};
